function Create-SetupScript {
    param([string]$OutputPath)
    
    try {
        Write-Log "Creating setup script..."
        
        $setupScriptContent = @"
# Windows Debloat Setup Script
# Run this script after Windows installation to apply debloat settings

Write-Host "Applying Windows debloat settings..." -ForegroundColor Green

# Import registry settings
Write-Host "Importing registry settings..." -ForegroundColor Yellow
reg import "%~dp0debloat-settings.reg"

# Disable unnecessary services
Write-Host "Disabling unnecessary services..." -ForegroundColor Yellow
$servicesToDisable = @(
    "DiagTrack",
    "dmwappushservice",
    "WSearch",
    "wuauserv",
    "WinDefend"
)

foreach ($service in $servicesToDisable) {
    try {
        Set-Service -Name $service -StartupType Disabled
        Stop-Service -Name $service -Force -ErrorAction SilentlyContinue
        Write-Host "Disabled service: $service" -ForegroundColor Green
    }
    catch {
        Write-Host "Failed to disable service: $service" -ForegroundColor Red
    }
}

# Remove bloatware apps
Write-Host "Removing bloatware apps..." -ForegroundColor Yellow
$appsToRemove = @(
    "Microsoft.3DBuilder",
    "Microsoft.BingFinance",
    "Microsoft.BingNews",
    "Microsoft.BingSports",
    "Microsoft.BingWeather",
    "Microsoft.GetHelp",
    "Microsoft.Getstarted",
    "Microsoft.MicrosoftOfficeHub",
    "Microsoft.MicrosoftSolitaireCollection",
    "Microsoft.MixedReality.Portal",
    "Microsoft.People",
    "Microsoft.SkypeApp",
    "Microsoft.WindowsAlarms",
    "Microsoft.WindowsFeedbackHub",
    "Microsoft.WindowsMaps",
    "Microsoft.ZuneMusic",
    "Microsoft.ZuneVideo"
)

foreach ($app in $appsToRemove) {
    try {
        Get-AppxPackage -Name $app -AllUsers | Remove-AppxPackage -ErrorAction SilentlyContinue
        Get-AppxProvisionedPackage -Online | Where-Object DisplayName -like "*$app*" | Remove-AppxProvisionedPackage -Online -ErrorAction SilentlyContinue
        Write-Host "Removed app: $app" -ForegroundColor Green
    }
    catch {
        Write-Host "Failed to remove app: $app" -ForegroundColor Red
    }
}

Write-Host "Debloat setup completed!" -ForegroundColor Green
Write-Host "Please restart your computer for all changes to take effect." -ForegroundColor Yellow
pause
"@
        
        $setupScriptFile = Join-Path $OutputPath "setup-debloat.ps1"
        $setupScriptContent | Out-File -FilePath $setupScriptFile -Encoding UTF8
        Write-Log "Created setup script"
        
        return $true
    }
    catch {
        Write-Log "ERROR: Failed to create setup script - $($_.Exception.Message)"
        return $false
    }
}

# Main execution
try {
    Write-Log "Starting simple Windows ISO debloat process..."
    Write-Log "Input Path: $InputPath"
    Write-Log "Output Path: $OutputPath"
    Write-Log "Windows Version: $WindowsVersion"
    
    # Tạo thư mục output nếu chưa tồn tại
    if (!(Test-Path $OutputPath)) {
        New-Item -ItemType Directory -Path $OutputPath -Force | Out-Null
        Write-Log "Created output directory: $OutputPath"
    }
    
    # Xử lý ISO files
    if (!(Copy-ISOWithOptimization -SourcePath $InputPath -Destination $OutputPath)) {
        throw "Failed to process ISO files"
    }
    
    # Tạo các file hỗ trợ
    if (!(Create-UnattendedSetupFiles -OutputPath $OutputPath)) {
        throw "Failed to create unattended setup files"
    }
    
    if (!(Create-SetupScript -OutputPath $OutputPath)) {
        throw "Failed to create setup script"
    }
    
    Write-Log "Simple Windows ISO debloat completed successfully!"
    Write-Host "Debloat completed successfully! Output files in: $OutputPath" -ForegroundColor Green
    
    # Hiển thị thông tin về các file đã tạo
    $outputFiles = Get-ChildItem -Path $OutputPath -Recurse
    Write-Host "`nCreated files:" -ForegroundColor Cyan
    foreach ($file in $outputFiles) {
        $relativePath = $file.FullName.Replace($OutputPath, "").TrimStart("\")
        Write-Host "  - $relativePath" -ForegroundColor White
    }
    
    exit 0
}
catch {
    Write-Log "ERROR: Critical error during debloat process - $($_.Exception.Message)"
    Write-Host "Debloat failed! Check logs for details." -ForegroundColor Red
    exit 1
}
finally {
    Write-Log "Simple debloat process finished"
} 